21		use work.data_rec_register_pkg.all;
22	
23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case0_pkg is
27	
28		constant CaseName_c : string := "Basic Functionality";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t;
35						signal FromDut	: in	Out_t);
36						
37	end top_tb_case0_pkg;
38	
39	------------------------------------------------------------------------------
40	-- Package Body
41	------------------------------------------------------------------------------
42	package body top_tb_case0_pkg is
43	
44		procedure run(	signal ms		: out	axi_ms_r;
45						signal sm		: in	axi_sm_r;
46						signal aclk		: in	std_logic;
47						signal Clk 		: in 	std_logic;
48						signal ToDut	: out	In_t;
49						signal FromDut	: in	Out_t) is
50			constant Samples_c 		: integer := MemoryDepth_v-4;
51			constant PreTrigger_c	: integer := MemoryDepth_v/2;
52			constant PostTrigger	: integer := Samples_c-PreTrigger_c;
53			constant UnusedSamples	: integer := 4;
54			variable startTime		: time;
55			variable doneTime		: time;
56			variable lastDoneCheck	: time;
57		begin
58			-- Print Message
59			print("Test: " & CaseName_c);
60			
61			-- check reset status
62			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Reset Status", 3, 0);
63			axi_single_expect(Reg_TrigCnt_Addr_c, 0, ms, sm, aclk, "Reset Trigger Counter");
64			axi_single_expect(Reg_DoneTime_Addr_c, 0, ms, sm, aclk, "Reset Done Counter");
65			axi_single_expect(Reg_TrigEna_Addr_c, 0, ms, sm, aclk, "Reset Trigger Enable");
66			assert FromDut.Done_Irq = '0' report "Initial State of Done_Irq was high" severity error;
67			
68			-- configure
69			axi_single_write(Reg_Pretrig_Addr_c, PreTrigger_c, ms, sm, aclk);
70			axi_single_expect(Reg_Pretrig_Addr_c, PreTrigger_c, ms, sm, aclk, "Pretrigger Readback");
71			axi_single_write(Reg_Totspl_Addr_c, Samples_c, ms, sm, aclk);
72			axi_single_expect(Reg_Totspl_Addr_c, Samples_c, ms, sm, aclk, "Totspl Readback");
73			lastDoneCheck := now;
74			
75			
76			-- Do two recordings to ensure things work not only once after reset
77			for i in 0 to 1 loop
78				-- Set trigger to high to check edge-sensitivity (and not level sensitivity)
79				ToDut.Trig_In(0) <= '1';			
80			
81				-- ARM
82				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
83				wait for 200 ns;
84				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StatePreTrig_c, ms, sm, aclk, "Pre Trigger Status", 3, 0);
85				assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;
86				lastDoneCheck := now;
87						
88				-- add pre trigger
89				InputSamples(PreTrigger_c+UnusedSamples, ToDut, Clk, 0);
90				wait for 100 ns;
91				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "Wait Trigger Status", 3, 0);	
92				assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after pre-trigger" severity error;
93				lastDoneCheck := now;
94				
95				-- Reset trigger to generate edges (if trigger was level sensitive, it would already have caused the recorder to trigger)
96				ToDut.Trig_In(0) <= '0';	
97				
98				-- No effect if disabled
99				axi_single_write(Reg_TrigEna_Addr_c, 0, ms, sm, aclk);
100				wait for 200 ns;
101				wait until rising_edge(Clk);
102				ToDut.Trig_In(0) <= '1';
103				wait until rising_edge(Clk);
104				ToDut.Trig_In(0) <= '0';
105				wait for 200 ns;
106				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "External Trigger Disabled, still Wait-Trigger", 3, 0);
107				wait for 200 ns;
108				axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_ExtIdx_c, ms, sm, aclk);	
109				axi_single_expect(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_ExtIdx_c, ms, sm, aclk, "Trigger Enable Readback");			
110				wait for 200 ns;
111				
112				-- start post trigger data			
113				InputSamples(1, ToDut, Clk, -1, 0);
114				wait for 100 ns;
115				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StatePostTrig_c, ms, sm, aclk, "Post Trigger Status", 3, 0);
116				assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after start post-trigger" severity error;
117				lastDoneCheck := now;
118				
119				-- end recording
120				InputSamples(PostTrigger, ToDut, Clk);
121				startTime := now;
122				InputSamples(MemoryDepth_v*1/2, ToDut, Clk);
123				wait for 10 us;
124				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
125				doneTime := now - startTime;
126				axi_single_expect(Reg_DoneTime_Addr_c, integer(doneTime/ClockPeriod_c), ms, sm, aclk, "Done Time 1", 31, 0, false, 15);
127				assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;
128				lastDoneCheck := now;
129				wait for 10 us;
130				axi_single_expect(Reg_DoneTime_Addr_c, integer(doneTime/ClockPeriod_c), ms, sm, aclk, "Done Time 2", 31, 0, false, 15);
131				-- automatic return to idle after reading done
132				wait for 400 ns;
133				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Idle Status 2", 3, 0);
134				axi_single_expect(Reg_TrigCnt_Addr_c, i+1, ms, sm, aclk, "Trigger Counter Counted");
135			
136				
137						
138				
139				-- Additional samples don't hurt
140				InputSamples(MemoryDepth_v*1/2, ToDut, Clk);
141				wait for 100 ns;
142				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Idle Status 3", 3, 0);
143				assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after going back to idle" severity error;
144				lastDoneCheck := now;
145				
146				-- Read data
147				CheckData(Samples_c, UnusedSamples, ms, sm, aclk);
148				assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after reading data" severity error;
149				lastDoneCheck := now;
150			end loop;
151			
152			-- Trigger Counter Reset
153			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_TrgCntClr_Idx_c, ms, sm, aclk);
154			wait for 200 ns;
155			axi_single_expect(Reg_TrigCnt_Addr_c, 0, ms, sm, aclk, "Trigger Counter Clear");
156			
157			
158			
159		end procedure;
160		
161		
162	end top_tb_case0_pkg;
