22	
23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case2_pkg is
27	
28		constant CaseName_c : string := "Self Triggered Mode";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t;
35						signal FromDut	: in	Out_t);
36						
37	end top_tb_case2_pkg;
38	
39	------------------------------------------------------------------------------
40	-- Package Body
41	------------------------------------------------------------------------------
42	package body top_tb_case2_pkg is
43	
44		procedure run(	signal ms		: out	axi_ms_r;
45						signal sm		: in	axi_sm_r;
46						signal aclk		: in	std_logic;
47						signal Clk 		: in 	std_logic;
48						signal ToDut	: out	In_t;
49						signal FromDut	: in	Out_t) is
50			constant SampleCount_c		: integer := 3;
51			constant PreTrigger_c		: integer := 1;
52			variable lastDoneCheck		: time;
53		begin
54			-- Print Message
55			print("Test: " & CaseName_c);
56			lastDoneCheck := now;
57			
58			-- Common configuration
59			axi_single_write(Reg_Totspl_Addr_c, SampleCount_c, ms, sm, aclk);
60			axi_single_write(Reg_Pretrig_Addr_c, PreTrigger_c, ms, sm, aclk);
61			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_SelfIdx_c, ms, sm, aclk);	
62			
63			-- Ch0 only, exit, no signedness
64			axi_single_write(Reg_SelftrigLo_Addr_c, -5, ms, sm, aclk);
65			axi_single_expect(Reg_SelftrigLo_Addr_c, -5, ms, sm, aclk, "Selftrig-Lo Readback Neg", 31, 0, true);
66			axi_single_write(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk);
67			axi_single_expect(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk, "Selftrig-Lo Readback Pos");
68			axi_single_write(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk);
69			axi_single_expect(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk, "Selftrig-Hi Readback Neg", 31, 0, true);
70			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
71			axi_single_expect(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk, "Selftrig-Hi Readback Pos");
72			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
73			axi_single_expect(Reg_SelftrigCfg_Addr_c, 1*2**0, ms, sm, aclk, "Selftrig-Cfg Readback - ENA", 7, 0);
74			axi_single_expect(Reg_SelftrigCfg_Addr_c, 1, ms, sm, aclk, "Selftrig-Cfg Readback - EXIT", Reg_SelftrigCfg_ExitSft_c, Reg_SelftrigCfg_ExitSft_c);
75			axi_single_expect(Reg_SelftrigCfg_Addr_c, 0, ms, sm, aclk, "Selftrig-Cfg Readback - ENTER", Reg_SelftrigCfg_EnterSft_c, Reg_SelftrigCfg_EnterSft_c);
76			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
77			wait for 300 ns;
78			assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;			-- done is only checked on first self-trigger
79			lastDoneCheck := now;
80			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 0, 1, 1);
81			wait for 100 ns;	
82			assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;			-- done is only checked on first self-trigger
83			lastDoneCheck := now;
84			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
85			CheckDataNoCh(SampleCount_c, 10, 1, 1, ms, sm, aclk);
86			
87			-- ch2 only, exit, no signedness
88			axi_single_write(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk);
89			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
90			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**2+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
91			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
92			wait for 100 ns;
93			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 0, 1, 1);
94			wait for 100 ns;
95			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
96			CheckDataNoCh(SampleCount_c, 10-2, 1, 1, ms, sm, aclk);	
97			
98			-- Ch0 only, enter, no signedness
99			axi_single_write(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk);
100			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
101			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_EnterSft_c, ms, sm, aclk);
102			axi_single_expect(Reg_SelftrigCfg_Addr_c, 0, ms, sm, aclk, "Selftrig-Cfg Readback - EXIT", Reg_SelftrigCfg_ExitSft_c, Reg_SelftrigCfg_ExitSft_c);
103			axi_single_expect(Reg_SelftrigCfg_Addr_c, 1, ms, sm, aclk, "Selftrig-Cfg Readback - ENTER", Reg_SelftrigCfg_EnterSft_c, Reg_SelftrigCfg_EnterSft_c);
104			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
105			wait for 100 ns;
106			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 0, 1, 1);
107			wait for 100 ns;
108			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
109			CheckDataNoCh(SampleCount_c, 4, 1, 1, ms, sm, aclk);		
110			
111			-- One of two channels, do not react on other channels
112			axi_single_write(Reg_SelftrigLo_Addr_c, 0, ms, sm, aclk);
113			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
114			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+1*2**1+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);		
115			-- Trigger on ch 0 
116			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
117			wait for 100 ns;
118			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 0, 100, 1);
119			wait for 100 ns;
120			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
121			CheckDataNoCh(SampleCount_c, 10, 100, 1, ms, sm, aclk);
122			-- No trigger on ch 2
123			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
124			wait for 100 ns;
125			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -200, 100, 1);
126			wait for 100 ns;
127			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "Waiting Status", 3, 0);		
128			-- Trigger on ch 1 
129			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
130			wait for 100 ns;
131			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -100, 100, 1);
132			wait for 100 ns;
133			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
134			CheckDataNoCh(SampleCount_c, 10-100, 100, 1, ms, sm, aclk);	
135			
136			-- Ch0 only, exit wihtout hitting the border, no signedness
137			axi_single_write(Reg_SelftrigLo_Addr_c, 0, ms, sm, aclk);
138			axi_single_write(Reg_SelftrigHi_Addr_c, 100, ms, sm, aclk);
139			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
140			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
141			wait for 100 ns;
142			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 5, 1, 10);
143			wait for 100 ns;
144			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
145			CheckDataNoCh(SampleCount_c, 95, 1, 10, ms, sm, aclk);		
146			
147			-- Signed range accross zero, exit
148			axi_single_write(Reg_SelftrigLo_Addr_c, -10, ms, sm, aclk);
149			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
150			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
151			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
152			wait for 100 ns;
153			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -20, 1, 1);
154			wait for 100 ns;
155			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
156			CheckDataNoCh(SampleCount_c, 10, 1, 1, ms, sm, aclk);		
157	
158			-- Signed range accross zero, enter		
159			axi_single_write(Reg_SelftrigLo_Addr_c, -10, ms, sm, aclk);
160			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
161			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_EnterSft_c, ms, sm, aclk);
162			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
163			wait for 100 ns;
164			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -20, 1, 1);
165			wait for 100 ns;
166			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
167			CheckDataNoCh(SampleCount_c, -11, 1, 1, ms, sm, aclk);		
168			
169			-- signed range below zero, exit
170			axi_single_write(Reg_SelftrigLo_Addr_c, -20, ms, sm, aclk);
171			axi_single_write(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk);
172			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
173			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
174			wait for 100 ns;
175			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -30, 1, 1);
176			wait for 100 ns;
177			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
178			CheckDataNoCh(SampleCount_c, -10, 1, 1, ms, sm, aclk);	
179			
180			-- signed range below zero, enter
181			axi_single_write(Reg_SelftrigLo_Addr_c, -20, ms, sm, aclk);
182			axi_single_write(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk);
183			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_EnterSft_c, ms, sm, aclk);
184			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
185			wait for 100 ns;
186			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -30, 1, 1);
187			wait for 100 ns;
188			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
189			CheckDataNoCh(SampleCount_c, -21, 1, 1, ms, sm, aclk);	
190	
191			-- Check no effect if not enabled, trigger afterwards to enter idle status again to be ready for next test
192			axi_single_write(Reg_TrigEna_Addr_c, 0, ms, sm, aclk);	
193			axi_single_write(Reg_SelftrigLo_Addr_c, -20, ms, sm, aclk);
194			axi_single_write(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk);
195			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_EnterSft_c, ms, sm, aclk);
196			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
197			wait for 200 ns;
198			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -30, 1, 1);		
199			wait for 200 ns;
200			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "No trigger when source disabled", 3, 0);
201			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_SelfIdx_c, ms, sm, aclk);	
202			wait for 200 ns;
203			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, -30, 1, 1);	
204			wait for 200 ns;
205			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
206			CheckDataNoCh(SampleCount_c, -21, 1, 1, ms, sm, aclk);			
207	
208			
209		end procedure;
210		
211		
212	end top_tb_case2_pkg;
