5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		
14	library std;
15		use std.textio.all;
16		
17	library work;
18		use work.psi_tb_axi_pkg.all;
19		use work.psi_tb_txt_util.all;
20		use work.top_tb_pkg.all;
21		use work.data_rec_register_pkg.all;
22	
23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case3_pkg is
27	
28		constant CaseName_c : string := "SW Trigger";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t;
35						signal FromDut	: in	Out_t);
36						
37	end top_tb_case3_pkg;
38	
39	------------------------------------------------------------------------------
40	-- Package Body
41	------------------------------------------------------------------------------
42	package body top_tb_case3_pkg is
43	
44		procedure run(	signal ms		: out	axi_ms_r;
45						signal sm		: in	axi_sm_r;
46						signal aclk		: in	std_logic;
47						signal Clk 		: in 	std_logic;
48						signal ToDut	: out	In_t;
49						signal FromDut	: in	Out_t) is
50			variable lastDoneCheck		: time;
51		begin
52			-- Print Message
53			print("Test: " & CaseName_c);
54			lastDoneCheck := now;
55			
56			-- configure
57			axi_single_write(Reg_Pretrig_Addr_c, 5, ms, sm, aclk);
58			axi_single_write(Reg_Totspl_Addr_c, 10, ms, sm, aclk);
59			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_SwIdx_c, ms, sm, aclk);	
60			
61			-- Check SW trigger between samples
62			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
63			wait for 200 ns;
64			assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;			-- done is only checked on first sw trigger
65			lastDoneCheck := now;
66			InputSamples(100, ToDut, Clk, 0);
67			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
68			wait for 200 ns;
69			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
70			wait for 200 ns;
71			InputSamples(100, ToDut, Clk);
72			assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;			-- done is only checked on first sw-trigger
73			lastDoneCheck := now;
74			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status 1", 3, 0);
75			CheckData(10, 95, ms, sm, aclk);
76			
77			-- Check correctness on second execution
78			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
79			InputSamples(100, ToDut, Clk, 100);
80			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
81			wait for 200 ns;
82			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
83			wait for 100 ns;
84			InputSamples(100, ToDut, Clk);
85			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status 2", 3, 0);
86			CheckData(10, 195, ms, sm, aclk);	
87			
88			-- Check SW trigger during samples
89			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
90			for i in 0 to NumOfInputs_c-1 loop
91				ToDut.In_Data(i) <= std_logic_vector(to_unsigned(i+1, InputWidth_c));
92			end loop;
93			ToDut.In_Vld <= '1';
94			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
95			wait for 200 ns;
96			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
97			wait for 200 ns;
98			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status 3", 3, 0);
99			CheckDataNoCh(10, 1, 1, 0, ms, sm, aclk);
100			ToDut.In_Vld <= '0';	
101			
102			-- Check SW trigger when unarmed (no action)
103			InputSamples(100, ToDut, Clk, 0);
104			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
105			wait for 200 ns;
106			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
107			wait for 200 ns;
108			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Idle Status", 3, 0);
109			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
110			wait for 200 ns;
111			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
112			wait for 200 ns;
113			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Idle Status", 3, 0);		
114			for i in 0 to 20 loop
115				InputSamples(1, ToDut, Clk, 0);
116				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateIdle_c, ms, sm, aclk, "Idle Status", 3, 0);
117			end loop;
118	
119			-- Check SW Trigger, maximum samples, no pre-trigger
120			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
121			axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);
122			axi_single_write(Reg_Totspl_Addr_c, MemoryDepth_v, ms, sm, aclk);
123			InputSamples(100, ToDut, Clk, 0);
124			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
125			wait for 200 ns;
126			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
127			wait for 200 ns;
128			InputSamples(100, ToDut, Clk);
129			CheckData(MemoryDepth_v, 100, ms, sm, aclk);
130	
131			-- Check no effect if SW trigger disabled as source
132			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
133			axi_single_write(Reg_TrigEna_Addr_c, 0, ms, sm, aclk);	
134			wait for 200 ns;
135			InputSamples(100, ToDut, Clk, 100);
136			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
137			wait for 200 ns;
138			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
139			InputSamples(100, ToDut, Clk);	
140			wait for 200 ns;
141			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "No effect when disabled", 3, 0);
142			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_SwIdx_c, ms, sm, aclk);	
143			wait for 200 ns;
144			axi_single_write(Reg_SwTrig_Addr_c, 1*2**Reg_SwTrig_TrigIdx_c, ms, sm, aclk);
145			wait for 200 ns;
146			axi_single_write(Reg_SwTrig_Addr_c, 0, ms, sm, aclk);
147			InputSamples(100, ToDut, Clk);		
148			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status 5", 3, 0);
149	
